// kaya runtime for Go guests: cgo, loading, the direct-ring occurrence
// loop, and submit. Hand-written; the wire vocabulary next to it
// (kaya_wire.go) is generated by kaya-bindgen.
//
// The direct tier: Go reads the occurrence ring with its own atomics —
// cgo is crossed only to start the core, to wait on an empty ring, and
// to submit. The consumer contract is the io_uring recipe documented in
// kaya.h. Call Init once, run the occurrence loop on one goroutine, and
// give kaya the process main thread via Run (runtime.LockOSThread in
// the caller's init).
package kaya

/*
#cgo CFLAGS: -I${SRCDIR}/../../crates/kaya/include -I${SRCDIR}/../.. -I${SRCDIR}
#cgo darwin LDFLAGS: -L${SRCDIR}/../../target/debug -lkaya -Wl,-rpath,${SRCDIR}/../../target/debug
#cgo windows LDFLAGS: -L${SRCDIR}/../.. -L${SRCDIR}/../../target/aarch64-pc-windows-msvc/release -lkaya
#cgo linux LDFLAGS: -L${SRCDIR}/../../target-linux/debug -lkaya -Wl,-rpath,${SRCDIR}/../../target-linux/debug
#include <kaya.h>
*/
import "C"

import (
	"fmt"
	"sync/atomic"
	"unsafe"
)

var ring C.KayaRingInfo

// Init fetches the ring layout. Call once, before the occurrence loop.
func Init() {
	C.kaya_occurrence_ring(&ring)
}

// Run enters the core on the calling thread (which must be the process
// main thread; use runtime.LockOSThread in an init function). Returns
// the exit code when the app ends.
// The stale-artifact guard, run once before the core takes the thread:
// this binding was generated from one spec revision; the loaded library
// must speak the same one.
func checkSpec() {
	if got := uint64(C.kaya_spec_hash()); got != SpecHash {
		panic(fmt.Sprintf(
			"kaya: library speaks spec %#016x, this binding was generated from %#016x — rebuild the library or regenerate bindings",
			got, SpecHash))
	}
}

func Run() int {
	checkSpec()
	return int(C.kaya_run())
}

// Submit sends one transaction: the concatenation of packed records
// (Tx* results), applied atomically.
func Submit(records ...[]byte) {
	var tx []byte
	for _, r := range records {
		tx = append(tx, r...)
	}
	C.kaya_submit((*C.uint8_t)(unsafe.Pointer(&tx[0])), C.size_t(len(tx)))
}

// RegisterBlob registers bulk payload bytes (an encoded image) with
// the core: one copy into core-owned memory, returning the u64 handle
// the next submit from this guest consumes (referenced or not). The
// caller's bytes are free to drop the moment this returns.
func RegisterBlob(data []byte) uint64 {
	if len(data) == 0 {
		// &data[0] does not exist for an empty slice; a one-byte
		// stand-in with length 0 keeps the C side off a null pointer.
		var zero C.uint8_t
		return uint64(C.kaya_blob_register(&zero, 0))
	}
	return uint64(C.kaya_blob_register((*C.uint8_t)(unsafe.Pointer(&data[0])), C.size_t(len(data))))
}

// NextOccurrence blocks for the next occurrence; ok is false when the
// core has shut down. keys is nil when id is a widget id, else id is a
// template node id and keys is the stamped copy's key path, outermost
// first. payload carries the entry's new text (string) for
// OccurrenceTextChanged, the checkbox's new state (bool) for
// OccurrenceToggled.
func NextOccurrence() (kind uint16, id uint64, keys []any, payload any, ok bool) {
	head := (*uint32)(unsafe.Pointer(ring.head))
	tail := (*uint32)(unsafe.Pointer(ring.tail))
	data := uintptr(unsafe.Pointer(ring.data))
	mask := uint32(ring.capacity) - 1

	h := atomic.LoadUint32(head)
	for {
		t := atomic.LoadUint32(tail) // acquire: records below are visible
		if h == t {
			if !C.kaya_wait_occurrences() {
				return 0, 0, nil, nil, false // shutdown
			}
			continue
		}
		at := data + uintptr(h&mask)
		size := *(*uint32)(unsafe.Pointer(at))
		rec := unsafe.Slice((*byte)(unsafe.Pointer(at)), size)
		kind, id, keys, payload, valid := ParseOccurrence(rec)
		h += size
		atomic.StoreUint32(head, h) // release: hand the space back
		if valid {
			return kind, id, keys, payload, true
		}
	}
}
